import xml.etree.ElementTree as ET
from urllib import request, error

def parseXML(xmlFile):
    try:
        tree = ET.parse(request.urlopen(xmlFile))
        root = tree.getroot()
        return dict(root)
    except error.URLError as e:
        print("Error: ",e)
        exit(-1)

if __name__ == "__main__":
    print(parseXML('https://raw.githubusercontent.com/jaceklaskowski/python-for-pentesters/master/.xml'))